import "./App.css";
import CounterPages from "./components/counterPages";
import { BrowserRouter, Routes, Route, Link,} from "react-router-dom";
import React, { Component } from "react";

class App extends Component {
  state = {
    pages: [
      { id: 1, name: "page #1", way: "/page1" },
      { id: 2, name: "page #2", way: "/page2" },
    ],
    index: {value: 1},
    next: "/page2",
    back: "/page0",
  };

  //adds a page of counters
  handleAddPage = () => {};

  //deletes selected page of counters
  handleDeletePage = () => {};

  //cycles forward a page to the next counter
  handleNextPage = () => {
    let index = {...this.state.index};
    index.value++;

    console.log(index);
    this.setState(index);
  };

  //cycles back a page to the previous counter
  handleBackPage = () => {
    let index = {...this.state.index};
    index.value--;
    this.setState(index);
  };

  render() {
    return (
      <BrowserRouter>
      <div>
        {/* <BrowserRouter>
        <BrowserRouter>
          <div>
    <Routes> */}
              <Route
                exact
                path={this.state.pages[this.state.index - 1].route}
                element={
                  <CounterPages>
                    id={this.state.pages[this.state.index - 1].id}
                    onAddPage={this.handleAddPage}
                    onDeletePage={this.handleDeletePage}
                    onNextPage={this.handleNextPage}
                    onBackPage={this.handleBackPage}
                    pages={this.state.pages}
                  </CounterPages>
                }
              ></Route>
             { /*</Routes> */}


              {/* <Routes>
              {this.state.pages.map(page => <Route
                exact
                path={page.way}
                element={
                  <CounterPages
                    key={page.id}
                    id={page.id}
                    onAddPage={this.handleAddPage}
                    onDeletePage={this.handleDeletePage}
                    onNextPage={this.handleNextPage}
                    onBackPage={this.handleBackPage}
                    pages={this.state.pages}>
                  </CounterPages>
                }
              ></Route>)}
              </Routes> */}


            {/* {
              <CounterPages>
                id={this.state.pages[this.state.index - 1].id}
                onAddPage={this.handleAddPage}
                onDeletePage={this.handleDeletePage}
                onNextPage={this.handleNextPage}
                onBackPage={this.handleBackPage}
              </CounterPages>
            } */}
        {/* this is for loading every page at once */}
        {/* <BrowserRouter>
      {this.state.pages.map(page => <CounterPages>
        id={page.id}
        onAddPage={this.handleAddPage}
        onDeletePage={this.handleDeletePage}
        </CounterPages>)}
        </BrowserRouter> */}
      </div>
      </BrowserRouter>
    );
  }

}

export default App;
